    //  获取读锁数量
    static int sharedCount(int c)    { return c >>> SHARED_SHIFT; }

    // 获取写锁数量
    static int exclusiveCount(int c) { return c & EXCLUSIVE_MASK; }

    protected final boolean isHeldExclusively() {
        // While we must in general read state before owner,
        // we don't need to do so to check if current thread is owner
        return getExclusiveOwnerThread() == Thread.currentThread();
    }
    /**
     * Returns the thread last set by {@code setExclusiveOwnerThread},
     * or {@code null} if never set.  This method does not otherwise
     * impose any synchronization or {@code volatile} field accesses.
     * @return the owner thread
     */
    protected final Thread getExclusiveOwnerThread() {
        return exclusiveOwnerThread;
    }
    /**
     * Sets the thread that currently owns exclusive access.
     * A {@code null} argument indicates that no thread owns access.
     * This method does not otherwise impose any synchronization or
     * {@code volatile} field accesses.
     * @param thread the owner thread
     */
    protected final void setExclusiveOwnerThread(Thread thread) {
        exclusiveOwnerThread = thread;
    }

获取共享锁（读锁）

tryReadLock()


/**
 * Performs tryLock for read, enabling barging in both modes.
 * This is identical in effect to tryAcquireShared except for
 * lack of calls to readerShouldBlock.
 */
@ReservedStackAccess
final boolean tryReadLock() {
    Thread current = Thread.currentThread();
    for (;;) {
        // 获取当前状态
        int c = getState();
        // 当前写锁不为0,且当前线程不为持有线程
        if (exclusiveCount(c) != 0 &&
            getExclusiveOwnerThread() != current)
            // 失败
            return false;
        // 只有没有写锁，且总数量不得越界时，才能尝试上锁
        // 获取读锁数量
        int r = sharedCount(c);
        // 超出最大值 uint16，会导致无法正确存储和计算
        if (r == MAX_COUNT)
            throw new Error("Maximum lock count exceeded");
        // 尝试CAS数量+1
        if (compareAndSetState(c, c + SHARED_UNIT)) {
            //成功
            if (r == 0) {
                // 如果之前没有读锁，设置为第一个读锁
                firstReader = current;
                firstReaderHoldCount = 1;
            } else if (firstReader == current) {
                // 如果有读锁，但就是当前线程，则+1
                firstReaderHoldCount++;
            } else {
                // 获取已缓存的锁
                HoldCounter rh = cachedHoldCounter;
                // 如果没有或者id不一致
                if (rh == null ||
                    rh.tid != LockSupport.getThreadId(current))
                    // 更新当前 cachedHoldCounter为当前线程的hold对象
                    cachedHoldCounter = rh = readHolds.get();
                else if (rh.count == 0)
                    // 如果rh.count==0，则说明没有进入线程变量中，则放入
                    readHolds.set(rh);
                // 计数+1
                rh.count++;
            }
            // 成功获取读锁，返回即可
            return true;
        }
        // 继续循环
    }
}


tryReadLock() 不会阻塞，因为是尝试，且会返回结果
firstReaderHold一组对象，为第一个线程重入等提供快速处理
对于后续频繁重入的同一线程，cachedHoldCounter 提供了第二道快速通路

